const btcKlines = $('03 — Binance BTC OHLCV').first().json;
const ethKlines = $('04 — Binance ETH OHLCV').first().json;

function calcRSI(klines, period) {
  const closes = klines.map(k => parseFloat(k[4]));
  let gains = [], losses = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i-1];
    gains.push(d > 0 ? d : 0);
    losses.push(d < 0 ? Math.abs(d) : 0);
  }
  const ag = gains.slice(0, period).reduce((a,b)=>a+b,0)/period;
  const al = losses.slice(0, period).reduce((a,b)=>a+b,0)/period;
  if (al === 0) return 100;
  return parseFloat((100 - 100/(1 + ag/al)).toFixed(2));
}

function calcEMA(prices, period) {
  const k = 2/(period+1);
  let ema = [prices[0]];
  for (let i = 1; i < prices.length; i++) ema.push(prices[i]*k + ema[i-1]*(1-k));
  return ema;
}

function calcMACD(klines) {
  const closes = klines.map(k => parseFloat(k[4]));
  const ema12 = calcEMA(closes, 12);
  const ema26 = calcEMA(closes, 26);
  const macdLine = ema12.map((v,i) => v - ema26[i]);
  const signal = calcEMA(macdLine.slice(-9), 9);
  const hist = macdLine[macdLine.length-1] - signal[signal.length-1];
  return {
    macd: parseFloat(macdLine[macdLine.length-1].toFixed(2)),
    signal: parseFloat(signal[signal.length-1].toFixed(2)),
    histogram: parseFloat(hist.toFixed(2)),
    trend: hist > 0 ? 'BULLISH' : 'BEARISH'
  };
}

function calcBB(klines) {
  const closes = klines.map(k => parseFloat(k[4]));
  const recent = closes.slice(-20);
  const sma = recent.reduce((a,b)=>a+b,0)/20;
  const std = Math.sqrt(recent.reduce((a,b)=>a+Math.pow(b-sma,2),0)/20);
  const upper = sma + 2*std;
  const lower = sma - 2*std;
  const cur = closes[closes.length-1];
  const pos = parseFloat(((cur-lower)/(upper-lower)*100).toFixed(1));
  return { upper: upper.toFixed(2), middle: sma.toFixed(2), lower: lower.toFixed(2), position: pos };
}

function rsiLabel(rsi) {
  if (rsi >= 70) return { emoji: '🔴', label: 'Overbought' };
  if (rsi >= 60) return { emoji: '🟠', label: 'Bullish' };
  if (rsi <= 30) return { emoji: '🟢', label: 'Oversold' };
  if (rsi <= 40) return { emoji: '🔵', label: 'Bearish' };
  return { emoji: '🟡', label: 'Neutral' };
}

const btcRSI = calcRSI(btcKlines, 14);
const ethRSI = calcRSI(ethKlines, 14);
const btcMACD = calcMACD(btcKlines);
const ethMACD = calcMACD(ethKlines);
const btcBB = calcBB(btcKlines);
const ethBB = calcBB(ethKlines);

return [{ json: {
  btcRSI, ethRSI,
  btcMACD, ethMACD,
  btcBB, ethBB,
  btcRSILabel: rsiLabel(btcRSI),
  ethRSILabel: rsiLabel(ethRSI)
}}];

const newsData = $('05 — CryptoPanic News').first().json;
const headlines = (newsData.results || []).slice(0, 10).map(n => n.title).join('\n');
return [{ json: { headlines } }];

