  return [{ json: JSON.parse(clean) }];
} catch(e) {
  return [{ json: { overallTone: 'Neutral', keyThemes: [], riskEvents: [], opportunities: [], marketImpact: 'Low', summary: 'Parse error.' } }];
}

const DISCORD_TOKEN = 'YOUR_DISCORD_BOT_TOKEN';
const CHANNEL_IDS = ['YOUR_CHANNEL_ID_1', 'YOUR_CHANNEL_ID_2'];

const keywords = ['bullish','bearish','buy','sell','moon','dump','pump','BTC','ETH','SOL','long','short','breakout','support','resistance','ATH','dip'];

let allMessages = [];

for (const channelId of CHANNEL_IDS) {
  try {
    const res = await fetch(`https://discord.com/api/v10/channels/${channelId}/messages?limit=50`, {
      headers: { 'Authorization': `Bot ${DISCORD_TOKEN}` }
    });
    if (!res.ok) throw new Error(`Status ${res.status}`);
    const msgs = await res.json();
    const filtered = msgs
      .filter(m => keywords.some(kw => m.content.toLowerCase().includes(kw.toLowerCase())))
      .map(m => ({ author: m.author.username, content: m.content, channelId }));
    allMessages = allMessages.concat(filtered);
  } catch(e) {
    console.log(`Discord channel ${channelId} error: ${e.message}`);
  }
}

const combinedText = allMessages.slice(0, 30).map(m => `[${m.author}]: ${m.content}`).join('\n') || 'No Discord messages found.';

return [{ json: { combinedText, totalMessages: allMessages.length } }];

